import 'package:flutter/material.dart';
import 'package:image_picker/image_picker.dart';
import 'package:aws_s3/aws_s3.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: PhotoUploadScreen(),
    );
  }
}

class PhotoUploadScreen extends StatefulWidget {
  @override
  _PhotoUploadScreenState createState() => _PhotoUploadScreenState();
}

class _PhotoUploadScreenState extends State<PhotoUploadScreen> {
  final ImagePicker _picker = ImagePicker();
  String _imageUrl = '';
  String _analysisResult = '';

  Future<void> _uploadPhoto() async {
    final pickedFile = await _picker.pickImage(source: ImageSource.gallery);
    if (pickedFile != null) {
      final awsS3 = AwsS3(
        accessKey: 'YOUR_AWS_ACCESS_KEY',
        secretKey: 'YOUR_AWS_SECRET_KEY',
        region: 'us-east-1',
        bucketId: 'your-bucket-name',
      );

      final uploadResult = await awsS3.uploadFile(
        file: pickedFile.path,
        fileName: 'uploaded_image.jpg',
      );

      if (uploadResult.success) {
        setState(() {
          _imageUrl = uploadResult.url;
        });
        _analyzeImage(uploadResult.url);
      }
    }
  }

  Future<void> _analyzeImage(String imageUrl) async {
    final response = await http.post(
      Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=YOUR_GOOGLE_CLOUD_API_KEY'),
      headers: {'Content-Type': 'application/json'},
      body: json.encode({
        'requests': [
          {
            'image': {'source': {'imageUri': imageUrl}},
            'features': [{'type': 'LABEL_DETECTION', 'maxResults': 10}]
          }
        ]
      }),
    );

    if (response.statusCode == 200) {
      final result = json.decode(response.body);
      setState(() {
        _analysisResult = result['responses'][0]['labelAnnotations']
            .map((label) => label['description'])
            .join(', ');
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Photo Upload & Analysis')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            if (_imageUrl.isNotEmpty) Image.network(_imageUrl),
            if (_analysisResult.isNotEmpty) Text('Analysis: $_analysisResult'),
            ElevatedButton(
              onPressed: _uploadPhoto,
              child: Text('Upload Photo'),
            ),
          ],
        ),
      ),
    );
  }
}